/*  THE 'DIV SOUP' ANTI-PATTERN */
// Looks like a button via CSS, but Screen Readers have no idea it's clickable.
// Also, keyboard users CANNOT use the 'Tab' key to reach it!
<div class="btn" onclick="submit()">Submit</div>

/*  SEMANTIC HTML */
// Automatically focusable via 'Tab' key.
// Screen reader announces 'Submit, Button'.
// Automatically responds to 'Enter' and 'Spacebar' presses.
<button onclick="submit()">Submit</button>
